SELECT student_id, MAX(difficulty_level) AS max_difficulty
FROM struggle
GROUP BY student_id;

SELECT MIN(difficulty_level) AS min_difficulty
FROM struggle
WHERE course_id = 0;

SELECT reason
FROM struggle
WHERE difficulty_level = (SELECT MAX(difficulty_level) FROM struggle);

SELECT COUNT(student_id) AS number_of_students_struggling
FROM struggle
WHERE difficulty_level = 2;

SELECT DATE(evaluation_date, 'unixepoch') AS formatted_date
FROM programming_structures
WHERE student_id = 1;

SELECT adviser_name
FROM advisers
WHERE department = 'Information Systems';
